const body = $input.first().json.body || $input.first().json;
const provider_id = parseInt(body.provider_id, 10);
const service_id = parseInt(body.service_id, 10);
const start_time = body.start_time;

if (isNaN(provider_id) || isNaN(service_id) || !start_time) {
  throw new Error('Missing core fields');
}

const duration = parseInt(body.duration_minutes || 60, 10);
const startDate = new Date(start_time);
const endDate = new Date(startDate.getTime() + duration * 60000);

const cleanTime = String(start_time).replace(/[^0-9]/g, '');
const idempotency_key = `booking_${provider_id}_${service_id}_${cleanTime}_${body.customer_id || body.chat_id || 'anon'}`;

const ctx = { 
  source: 'WF2_Booking_Orchestrator', 
  version: '3.2', 
  started_at: new Date().toISOString() 
};

return [{ json: {
  provider_id, 
  service_id, 
  start_time, 
  end_time: endDate.toISOString(),
  duration_minutes: duration,
  user_id: parseInt(body.user_id || 0, 10) || null, customer_id: body.customer_id || null,
  chat_id: body.chat_id || null,
  event_title: body.event_title || 'Appointment',
  idempotency_key,
  original_body: body,
  _meta: ctx
}}];

const items = $input.all();
const dup = (items.length > 0 && items[0].json.booking_id) ? items[0].json : null;
return [{ json: { 
  _is_dup: !!dup, 
  _dup: dup 
} }];

return [{ json: {
  success: true,
  error_code: null,
  data: {
    booking_id: $('Process Idemp').first().json._dup.booking_id,
    status: $('Process Idemp').first().json._dup.status,
    gcal_event_id: $('Process Idemp').first().json._dup.gcal_event_id,
    is_duplicate: true
  },
  _meta: $('Validate').first().json._meta
}}];

const res = $input.first().json;
const ok = res.data?.acquired === true;
return [{ json: { 
  _lock_ok: ok, 
  _lock_key: res.data?.lock_key, 
  _owner_token: res.data?.owner_token,
  _lock_err: res.error || (res.success === false ? res.error_message : null)
}}];

return [{ json: {
  success: false,
  error_code: 'LOCK_DENIED',
  data: {
    error: $('Process Lock').first().json._lock_err
  },
  _meta: $('Validate').first().json._meta
}}];

const res = $input.first().json;
const ok = res.data?.allowed === true;
return [{ json: { 
  _cb_ok: ok, 
  _cb_err: res.error || null 
} }];

return [{ json: {
  success: false,
  error_code: 'CB_OPEN',
  data: {
    service: 'google_calendar'
  },
  _meta: $('Validate').first().json._meta
}}];

const res = $input.first().json;
const ok = res.data?.available === true;
return [{ json: { 
  _avail_ok: ok, 
  _avail_err: res.error || null 
} }];

return [{ json: {
  success: false,
  error_code: 'NOT_AVAILABLE',
  data: {
    message: 'Slot no longer available'
  },
  _meta: $('Validate').first().json._meta
}}];

const res = $input.first().json;
const ok = !!res.id;
return [{ json: { 
  _gcal_ok: ok, 
  _gcal_id: res.id || null, 
  _gcal_err: res.message || null 
} }];

return [{ json: {
  success: false,
  error_code: 'GCAL_ERROR',
  data: {
    error: $('Process GCal').first().json._gcal_err
  },
  _meta: $('Validate').first().json._meta
}}];

const res = $input.first().json;
const ok = !!res.id;
return [{ json: { 
  _db_ok: ok, 
  _db_id: res.id || null, 
  _db_err: res.message || null 
} }];

return [{ json: {
  success: false,
  error_code: 'DB_ERROR',
  data: {
    error: $('Process DB').first().json._db_err
  },
  _meta: $('Validate').first().json._meta
}}];

return [{ json: {
  success: true,
  error_code: null,
  data: {
    booking_id: $('Process DB').first().json._db_id,
    gcal_event_id: $('Process GCal').first().json._gcal_id
  },
  _meta: $('Validate').first().json._meta
}}];
